+                bytes_to_free_after: initial_state.bytes_to_free,
+            };
+        }
+
+        let sample_limit = sample_limit.max(1);
+        let mut cursor = 0usize;
+        let mut sampled_keys = 0usize;
+        let mut evicted_keys = 0usize;
+        let mut bytes_freed = 0usize;
